public int subsetXORSum(int[] nums) {
    int result = 0;
    int n = nums.length;
    int numSubsets = 1 << n;

    for (int i = 0; i < numSubsets; i++) {
        int subsetXOR = 0;
        for (int j = 0; j < n; j++) {
            if ((i & (1 << j)) != 0) {
                subsetXOR ^= nums[j];
            }
        }
        result += subsetXOR;
    }

    return result;
}
